def min_partition_diff(A):
    total_sum = sum(A)
    n = len(A)
    dp = [[False] * (total_sum + 1) for _ in range(n + 1)]
    dp[0][0] = True

    for i in range(1, n + 1):
        for j in range(total_sum + 1):
            if j < A[i - 1]:
                dp[i][j] = dp[i - 1][j]
            else:
                dp[i][j] = dp[i - 1][j] or dp[i - 1][j - A[i - 1]]

    min_diff = float('inf')
    for j in range(total_sum + 1):
        if dp[n][j]:
            diff = abs(2 * j - total_sum)
            min_diff = min(min_diff, diff)

    return min_diff

